div.script:
// 選擇所有容器
const containers = document.querySelectorAll('.s_custom_fullImgHoevr1 .s_custom_boxWrap');
// 檢查是否為非編輯模式
if (!document.body.classList.contains('editor_started')) {
    // 初始化：預設第一個容器內的 div 為 .show
    if (containers.length > 0) {
        const firstDiv = containers[0].querySelector('div');
        if (firstDiv) {
            firstDiv.classList.add('show');
        }
    }
    // 綁定事件處理器到每個容器內的 .btn-wrap
    containers.forEach(container => {
        const btnWrap = container.querySelector('.btn-wrap'); // 找到內層的 .btn-wrap
        if (btnWrap) {
            btnWrap.addEventListener('mouseenter', function () {
                // 移除其他容器內的 .show
                containers.forEach(otherContainer => {
                    const div = otherContainer.querySelector('div');
                    if (div) {
                        div.classList.remove('show');
                    }
                });
                // 為當前容器內的 div 添加 .show
                const currentDiv = container.querySelector('div'); // 基於當前 container 操作
                if (currentDiv) {
                    currentDiv.classList.add('show');
                }
            });
        }
    });
}

document.addEventListener('DOMContentLoaded', function () {
  // 確認 body 上是否沒有 'editor_started' class，才執行邏輯
  if (!document.body.classList.contains('editor_started')) {
    const containers = document.querySelectorAll('.s_custom_fullImgHoevr2 .s_custom_boxWrap');
    // 先移除所有 .container-fluid 的 show class
    containers.forEach(container => {
      const fluid = container.querySelector('.container-fluid');
      if (fluid) fluid.classList.remove('show');
    });
    // 預設第一個 section 的 .container-fluid 加上 show
    if (containers.length > 0) {
      const firstContainer = containers[0].querySelector('.container-fluid');
      if (firstContainer) {
        firstContainer.classList.add('show');
      }
    }
    // 滑入互動事件
    containers.forEach(container => {
      container.addEventListener('mouseenter', function () {
        containers.forEach(c => {
          const div = c.querySelector('.container-fluid');
          if (div) div.classList.remove('show');
        });
        const currentDiv = this.querySelector('.container-fluid');
        if (currentDiv) currentDiv.classList.add('show');
      });
    });
  }
});

    document.querySelector('.s_custom_controlBtn').addEventListener('click', function() {
    // 檢查 <body> 是否有 .editor_started 類別
    if (!document.body.classList.contains('editor_started')) {
        document.querySelector('.s_custom_exhibitionUpdates.s_custom_fixed').classList.toggle('active');
    }
});

document.addEventListener("DOMContentLoaded", function () {
    if (document.body.classList.contains("editor_started")) return;
    // 防抖函式，避免頻繁觸發
    function debounce(fn, delay) {
        let timer = null;
        return function (...args) {
            clearTimeout(timer);
            timer = setTimeout(() => fn.apply(this, args), delay);
        };
    }
    // 合併同一容器內多個 .row 的子元素
    function mergeRows(container) {
        const rows = Array.from(container.children).filter(child => child.classList.contains('row'));
        if (rows.length > 1) {
            const firstRow = rows[0];
            for (let i = 1; i < rows.length; i++) {
                const currentRow = rows[i];
                while (currentRow.firstElementChild) {
                    firstRow.appendChild(currentRow.firstElementChild);
                }
                currentRow.remove();
            }
        }
    }
    // 平滑滾動函式（含緩動）
    function smoothScrollBy(container, distance, duration = 300) {
        const start = container.scrollLeft;
        const startTime = performance.now();
        function scrollStep(timestamp) {
            const elapsed = timestamp - startTime;
            const progress = Math.min(elapsed / duration, 1);
            const ease = 0.5 - Math.cos(progress * Math.PI) / 2;
            container.scrollLeft = start + distance * ease;
            if (progress < 1) {
                requestAnimationFrame(scrollStep);
            }
        }
        requestAnimationFrame(scrollStep);
    }
    let isScrollingLocked = false;
    const scrollCooldown = 800;
    // 初始化每個 row 元素的滾動與箭頭行為
    function initRowElements() {
        const rowElements = document.querySelectorAll(".s_custom_productRightScroll >[class*=container]>[class*=_snippet_template]>.row");
        rowElements.forEach((rowElement) => {
            rowElement.style.overflowX = "auto";
            rowElement.style.overflowY = "hidden";
            rowElement.style.overscrollBehaviorX = "contain";
            // 檢查箭頭是否已存在，若無才新增
            let leftArrow = rowElement.parentElement.querySelector('.carousel-arrow-left');
            let rightArrow = rowElement.parentElement.querySelector('.carousel-arrow-right');
            if (!leftArrow) {
                leftArrow = document.createElement("div");
                leftArrow.classList.add("carousel-arrow", "carousel-arrow-left");
                leftArrow.innerHTML = '<i class="fa fa-angle-left" aria-hidden="true"></i>';
                rowElement.parentElement.appendChild(leftArrow);
            }
            if (!rightArrow) {
                rightArrow = document.createElement("div");
                rightArrow.classList.add("carousel-arrow", "carousel-arrow-right");
                rightArrow.innerHTML = '<i class="fa fa-angle-right" aria-hidden="true"></i>';
                rowElement.parentElement.appendChild(rightArrow);
            }
            // 如果沒有橫向卷軸，就隱藏箭頭
            const isScrollable = rowElement.scrollWidth > rowElement.clientWidth;
            leftArrow.style.display = isScrollable ? 'block' : 'none';
            rightArrow.style.display = isScrollable ? 'block' : 'none';
            // 滾動事件控制箭頭啟用狀態
            rowElement.addEventListener("scroll", function () {
                const maxScrollLeft = rowElement.scrollWidth - rowElement.clientWidth;
                const currentScrollLeft = rowElement.scrollLeft;
                leftArrow.classList.toggle("disabled", currentScrollLeft <= 0);
                rightArrow.classList.toggle("disabled", currentScrollLeft >= maxScrollLeft);
            });
            // 滑鼠滾輪滾動（含上下頁切換）
            rowElement.addEventListener(
                "wheel",
                function (e) {
                    const maxScrollLeft = rowElement.scrollWidth - rowElement.clientWidth;
                    const currentScrollLeft = rowElement.scrollLeft;
                    const atLeftEdge = currentScrollLeft <= 0;
                    const atRightEdge = currentScrollLeft >= maxScrollLeft;
                    if ((atLeftEdge && e.deltaY < 0) || (atRightEdge && e.deltaY > 0)) {
                        if (isScrollingLocked) return;
                        e.preventDefault();
                        isScrollingLocked = true;
                        setTimeout(() => {
                            isScrollingLocked = false;
                        }, scrollCooldown);
                    } else {
                        e.preventDefault();
                        smoothScrollBy(rowElement, e.deltaY * 2, 400);
                    }
                },
                { passive: false }
            );
            // 左箭頭點擊事件
            leftArrow.addEventListener("click", function () {
                const scrollDistance = getComputedStyle(document.documentElement).getPropertyValue('--scroll-distance');
                const distance = parseFloat(scrollDistance) * window.innerWidth / 100;
                smoothScrollBy(rowElement, -distance);
            });
            // 右箭頭點擊事件
            rightArrow.addEventListener("click", function () {
                const scrollDistance = getComputedStyle(document.documentElement).getPropertyValue('--scroll-distance');
                const distance = parseFloat(scrollDistance) * window.innerWidth / 100;
                smoothScrollBy(rowElement, distance);
            });
        });
    }
    // 主流程：合併 row 並初始化
    function processContainers() {
        const containers = document.querySelectorAll('.s_custom_productRightScroll >[class*=container]>[class*=_snippet_template]');
        containers.forEach(container => {
            mergeRows(container);
        });
        initRowElements();
    }
    // 監聽 .dynamic_snippet_template 內部新增元素
    function startObserver() {
        const targets = document.querySelectorAll('.s_custom_productRightScroll >[class*=container]>[class*=_snippet_template]');
        if (targets.length === 0) {
            setTimeout(startObserver, 300); // 等待動態生成
            return;
        }
        const debouncedProcess = debounce(processContainers, 200);
        const observer = new MutationObserver((mutationsList) => {
            for (const mutation of mutationsList) {
                if (mutation.type === 'childList' && mutation.addedNodes.length > 0) {
                    debouncedProcess();
                    break;
                }
            }
        });
        targets.forEach(target => {
            observer.observe(target, { childList: true, subtree: false });
        });
    }
    // 頁面載入時先執行一次初始化
    processContainers();
    // 啟動監聽器
    startObserver();
});

    document.addEventListener("DOMContentLoaded", () => {
    const body = document.body;
    // 僅在非編輯模式下執行
    if (!body.classList.contains("editor_started")) {
        const infoElements = document.querySelectorAll(".map-description-content > .s_text");
        const dotLists = document.querySelectorAll(".map-brief-description > .s_text");
        // 預設為 info-1 和 dot-list.e-tech
        const defaultActiveInfo = document.querySelector(".map-description-content > .s_text:first-child");
        const defaultActiveDot = document.querySelector(".map-brief-description > .s_text:first-child");
        if (defaultActiveInfo && defaultActiveDot) {
            defaultActiveInfo.classList.add("active");
            defaultActiveDot.classList.add("active");
        }
        infoElements.forEach((infoElement, index) => {
            infoElement.addEventListener("mouseenter", () => {
                // 清除所有 active 狀態
                infoElements.forEach(info => info.classList.remove("active"));
                dotLists.forEach(dot => dot.classList.remove("active"));
                // 為當前 info 和對應的 dot-list 加上 active
                const targetDot = dotLists[index];
                if (infoElement && targetDot) {
                    infoElement.classList.add("active");
                    targetDot.classList.add("active");
                }
            });
        });
    }
});

    document.addEventListener("DOMContentLoaded", function () {
        if (document.body.classList.contains("editor_started")) return;
        (function () {
  const oldSections = document.querySelectorAll('.s_custom_anchorArea');
  if (oldSections.length === 0) return;
  const firstSection = oldSections[0];
  const targetRow = firstSection.querySelector('.row');
  if (!targetRow) return;
  // 預先蒐集所有 col 元素
  const colElements = [];
  oldSections.forEach((section, sectionIndex) => {
    const id = section.getAttribute('id');
    const isAnchor = section.getAttribute('data-anchor') === 'true';
    const cols = section.querySelectorAll('[class*="col-lg"]');
    cols.forEach((col, colIndex) => {
      const clone = col.cloneNode(true);
      // 將 id 和 data-anchor 僅放在每區塊的第一個 col 上
      if (colIndex === 0 && isAnchor && id) {
        clone.setAttribute('id', id);
        clone.setAttribute('data-anchor', 'true');
      }
      colElements.push(clone);
    });
  });
  // 清空第一個 section 的 row
  targetRow.innerHTML = '';
  // 將整理好的 col 加回第一個 row
  colElements.forEach(col => targetRow.appendChild(col));
  // 清除第一個 section 的 id 和 data-anchor 屬性
  firstSection.removeAttribute('id');
  firstSection.removeAttribute('data-anchor');
  // 移除其他多餘的 section
  oldSections.forEach((section, i) => {
    if (i !== 0) section.remove();
  });
})();
    });

document.addEventListener('DOMContentLoaded', function () {
  const isLargeScreen = window.innerWidth > 991;
  // 監聽 body class 變化，編輯模式時移除動態內容
  const observer = new MutationObserver(function (mutations) {
    mutations.forEach(function (mutation) {
      if (mutation.type === 'attributes' && mutation.target.classList.contains('editor_started')) {
        document.querySelectorAll('.cus-wrap').forEach(wrap => wrap.remove());
      }
    });
  });
  observer.observe(document.body, {
    attributes: true,
    attributeFilter: ['class'],
  });
  // 如果不是編輯模式且是大螢幕，執行主邏輯
  if (!document.body.classList.contains('editor_started') && isLargeScreen) {
    const sections = document.querySelectorAll('.s_custom_fullHoverBackground');
    sections.forEach(sectionBlock => {
      // 跳過有 s_custom_hidden 的
      if (sectionBlock.classList.contains('s_custom_hidden')) return;
      const section = sectionBlock.querySelector('.s_product_product_horizontal');
      if (!section) return;
      // 避免重複插入
      if (section.querySelector('.cus-wrap')) return;
      let bg1 = sectionBlock.querySelector('.bg-image.bg1');
      let bg2 = sectionBlock.querySelector('.bg-image.bg2');
      if (!bg1 || !bg2) {
        bg1 = document.createElement('div');
        bg2 = document.createElement('div');
        bg1.className = 'bg-image bg1 active';
        bg2.className = 'bg-image bg2';
        sectionBlock.appendChild(bg1);
        sectionBlock.appendChild(bg2);
      }
      const switchBackground = function (url) {
        const current = sectionBlock.querySelector('.bg-image.active');
        const next = current === bg1 ? bg2 : bg1;
        next.style.backgroundImage = `url('${url}')`;
        next.classList.add('active');
        current.classList.remove('active');
      };
      // 建立自定義資訊與按鈕結構
      const wrap = document.createElement('div');
      wrap.className = 'cus-wrap';
      const infoWrap = document.createElement('div');
      infoWrap.className = 'cus-info-wrap';
      const btnWrap = document.createElement('div');
      btnWrap.className = 'cus-btn-wrap';
      const cards = section.querySelectorAll('.o_carousel_product_card');
      cards.forEach((card, index) => {
        const info = card.querySelector('.o_carousel_product_card_body .info-wrap');
        const btn = card.querySelector('.d-flex.justify-content-between');
        const infoList = document.createElement('div');
        infoList.className = 'cus-info-list';
        if (info) infoList.appendChild(info.cloneNode(true));
        infoWrap.appendChild(infoList);
        const btnList = document.createElement('div');
        btnList.className = 'cus-btn-list';
        if (btn) {
          const btnIcon = btn.querySelector('.cus-icon-btn');
          if (btnIcon) btnList.appendChild(btnIcon.cloneNode(true));
        }
        btnList.dataset.index = index;
        btnWrap.appendChild(btnList);
      });
      wrap.appendChild(infoWrap);
      wrap.appendChild(btnWrap);
      section.appendChild(wrap);
      // 預設顯示第一個
      const btnLists = wrap.querySelectorAll('.cus-btn-list');
      const infoLists = wrap.querySelectorAll('.cus-info-list');
      if (btnLists[0]) btnLists[0].classList.add('active');
      if (infoLists[0]) infoLists[0].classList.add('show');
      const defaultImg = cards[0]?.querySelector('.position-static img');
      if (defaultImg?.src) switchBackground(defaultImg.src);
      // 滑入切換
      btnLists.forEach((btn, idx) => {
        btn.addEventListener('mouseenter', () => {
          btnLists.forEach(b => b.classList.remove('active'));
          infoLists.forEach(i => i.classList.remove('show'));
          btn.classList.add('active');
          if (infoLists[idx]) infoLists[idx].classList.add('show');
          const img = cards[idx]?.querySelector('.position-static img');
          if (img?.src) switchBackground(img.src);
        });
      });
      // 額外插入 .s_custom_allCatBtn
      const allCatBlock = sectionBlock.querySelector('.s_custom_allCatBtn');
      if (allCatBlock) {
        const allBtns = allCatBlock.querySelectorAll('a.btn');
        if (allBtns.length > 0) {
          const allBtnWrap = document.createElement('div');
          allBtnWrap.className = 'cus-all-btn-wrap';
          allBtns.forEach(btn => allBtnWrap.appendChild(btn.cloneNode(true)));
          btnWrap.insertAdjacentElement('afterend', allBtnWrap);
        }
      }
    });
  }
});

document.addEventListener("DOMContentLoaded", function () {
    function debounce(fn, delay) {
        let timer = null;
        return function (...args) {
            clearTimeout(timer);
            timer = setTimeout(() => fn.apply(this, args), delay);
        };
    }
    function smoothScrollBy(container, distance, duration = 400) {
        const start = container.scrollLeft;
        const startTime = performance.now();
        function scrollStep(timestamp) {
            const elapsed = timestamp - startTime;
            const progress = Math.min(elapsed / duration, 1);
            const ease = 0.5 - Math.cos(progress * Math.PI) / 2;
            container.scrollLeft = start + distance * ease;
            if (progress < 1) requestAnimationFrame(scrollStep);
        }
        requestAnimationFrame(scrollStep);
    }
    function getScrollDistance() {
        let raw = getComputedStyle(document.documentElement)
            .getPropertyValue('--scroll-distance2').trim();
        if (raw.endsWith('px')) {
            return parseFloat(raw);
        } else if (raw.endsWith('%')) {
            return window.innerWidth * (parseFloat(raw) / 100);
        } else {
            // 如果沒有單位，直接當成 px
            return parseFloat(raw);
        }
    }
    let isScrollingLocked = false;
    const scrollCooldown = 800;
    function initAccordions() {
        const accordions = document.querySelectorAll(".s_custom_worldwide:not(.s_custom_hidden) .accordion");
        accordions.forEach(accordion => {
            accordion.style.overflowX = "auto";
            accordion.style.overflowY = "hidden";
            accordion.style.overscrollBehaviorX = "contain";
            const isScrollable = accordion.scrollWidth > accordion.clientWidth;
            let leftArrow = accordion.parentElement.querySelector('.carousel-arrow-left');
            let rightArrow = accordion.parentElement.querySelector('.carousel-arrow-right');
            if (!isScrollable) {
                if (leftArrow) leftArrow.remove();
                if (rightArrow) rightArrow.remove();
                return;
            }
            if (!leftArrow) {
                leftArrow = document.createElement("div");
                leftArrow.classList.add("carousel-arrow", "carousel-arrow-left");
                leftArrow.innerHTML = '<i class="fa fa-angle-left" aria-hidden="true"></i>';
                accordion.insertAdjacentElement("afterend", leftArrow);
            }
            if (!rightArrow) {
                rightArrow = document.createElement("div");
                rightArrow.classList.add("carousel-arrow", "carousel-arrow-right");
                rightArrow.innerHTML = '<i class="fa fa-angle-right" aria-hidden="true"></i>';
                leftArrow.insertAdjacentElement("afterend", rightArrow);
            }
            accordion.addEventListener("scroll", function () {
                const maxScrollLeft = accordion.scrollWidth - accordion.clientWidth;
                leftArrow.classList.toggle("disabled", accordion.scrollLeft <= 0);
                rightArrow.classList.toggle("disabled", accordion.scrollLeft >= maxScrollLeft);
            });
            accordion.addEventListener("wheel", function (e) {
                const maxScrollLeft = accordion.scrollWidth - accordion.clientWidth;
                const atLeftEdge = accordion.scrollLeft <= 0;
                const atRightEdge = accordion.scrollLeft >= maxScrollLeft;
                if ((atLeftEdge && e.deltaY < 0) || (atRightEdge && e.deltaY > 0)) {
                    if (isScrollingLocked) return;
                    e.preventDefault();
                    isScrollingLocked = true;
                    setTimeout(() => isScrollingLocked = false, scrollCooldown);
                } else {
                    e.preventDefault();
                    smoothScrollBy(accordion, e.deltaY * 2, 400);
                }
            }, { passive: false });
            leftArrow.addEventListener("click", function () {
                smoothScrollBy(accordion, -getScrollDistance(), 400);
            });
            rightArrow.addEventListener("click", function () {
                smoothScrollBy(accordion, getScrollDistance(), 400);
            });
        });
    }
    function removeArrows() {
        document.querySelectorAll('.carousel-arrow-left, .carousel-arrow-right').forEach(el => el.remove());
    }
    const observer = new MutationObserver(function (mutations) {
        mutations.forEach(function (mutation) {
            if (mutation.type === 'attributes' && mutation.attributeName === 'class') {
                if (document.body.classList.contains('editor_started')) {
                    removeArrows();
                } else {
                    initAccordions();
                }
            }
        });
    });
    observer.observe(document.body, { attributes: true });
    if (!document.body.classList.contains("editor_started")) {
        initAccordions();
    }
});

